from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from flask_mail import Mail, Message
import os
import secrets
from itsdangerous import URLSafeTimedSerializer, BadSignature, SignatureExpired

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///users.db'
app.config['MAIL_SERVER'] = 'smtp.example.com'
app.config['MAIL_PORT'] = 587
app.config['MAIL_USERNAME'] = os.environ.get('MAIL_USERNAME')
app.config['MAIL_PASSWORD'] = os.environ.get('MAIL_PASSWORD')
app.config['MAIL_USE_TLS'] = True
app.config['MAIL_USE_SSL'] = False
db = SQLAlchemy(app)
mail = Mail(app)
s = URLSafeTimedSerializer(os.environ.get('SECRET_KEY'))

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), unique=True, nullable=False)
    mfa_enabled = db.Column(db.Boolean, default=False)

@app.route('/reset-mfa', methods=['POST'])
def reset_mfa():
    data = request.get_json()
    email = data.get('email')
    user = User.query.filter_by(email=email).first()
    
    if user:
        token = s.dumps(email, salt='mfa-reset')
        reset_link = f"http://localhost:5000/reset-mfa-confirm/{token}"
        msg = Message('Reset MFA', sender='noreply@example.com', recipients=[email])
        msg.body = f'Click the link to reset your MFA settings: {reset_link}'
        mail.send(msg)
        return jsonify({'message': 'Reset link sent to your email.'}), 200
    return jsonify({'message': 'Email not found.'}), 404

@app.route('/reset-mfa-confirm/<token>', methods=['GET'])
def reset_mfa_confirm(token):
    try:
        email = s.loads(token, salt='mfa-reset', max_age=3600)
    except (BadSignature, SignatureExpired):
        return jsonify({'message': 'Invalid or expired token.'}), 400

    user = User.query.filter_by(email=email).first()
    if user:
        user.mfa_enabled = False
        db.session.commit()
        return jsonify({'message': 'MFA has been disabled.'}), 200
    return jsonify({'message': 'User not found.'}), 404

@app.route('/enable-mfa', methods=['POST'])
def enable_mfa():
    data = request.get_json()
    email = data.get('email')
    user = User.query.filter_by(email=email).first()
    
    if user:
        user.mfa_enabled = True
        db.session.commit()
        return jsonify({'message': 'MFA enabled.'}), 200
    return jsonify({'message': 'User not found.'}), 404

@app.route('/disable-mfa', methods=['POST'])
def disable_mfa():
    data = request.get_json()
    email = data.get('email')
    user = User.query.filter_by(email=email).first()
    
    if user:
        user.mfa_enabled = False
        db.session.commit()
        return jsonify({'message': 'MFA disabled.'}), 200
    return jsonify({'message': 'User not found.'}), 404

if __name__ == '__main__':
    db.create_all()
    app.run(debug=False)